def add_space_to_binary(binary_string):
    # Create a list to hold chunks of 8 characters
    chunks = []

    # Iterate over the binary string with a step of 8
    for i in range(0, len(binary_string), 8):
        # Slice the string to get a chunk of 8 characters
        chunk = binary_string[i:i+8]
        # Append the chunk to the list
        chunks.append(chunk)

    # Join the list of chunks with a space to insert spaces between them
    spaced_binary_string = ' '.join(chunks)

    return spaced_binary_string

def main():
    print("test")
    binary_string = ""
    print(add_space_to_binary(binary_string))

if __name__ == "__main__":
    main()